const payload = msg.payload;
if (!payload || !payload.alerts) return null;

const alerts = payload.alerts;
let msgText = `🔔 *IMS SYSTEM ALERT [${(payload.status || 'unknown').toUpperCase()}]* 🔔\n\n`;

for (let i = 0; i < alerts.length; i++) {
    const a = alerts[i];
    const labels = a.labels || {};
    const annotations = a.annotations || {};

    let icon = '⚠️';
    if (labels.severity === 'critical') icon = '🔥';
    if (payload.status === 'resolved') icon = '✅';

    const alertname = labels.alertname || 'Unknown Alert';
    const host = labels.machine_id || labels.instance || 'System';
    const summary = annotations.summary || 'N/A';
    const desc = annotations.description ? `\n💡 *Desc:* ${annotations.description}` : '';
    const startTime = a.startsAt ? new Date(a.startsAt).toLocaleString('th-TH') : 'Unknown';

    msgText += `${icon} *${alertname}*\n🖥️ *Host:* ${host}\n📝 *Detail:* ${summary}${desc}\n🕒 *Time:* ${startTime}\n-------------------\n`;
}

if (msgText.length > 4000) {
    msgText = msgText.substring(0, 4000) + '\n\n... [TRUNCATED: Too many alerts!]';
}
msg.payload = msgText;
return msg;

const token = env.get('LINE_CHANNEL_ACCESS_TOKEN') || '';
const userId = env.get('LINE_USER_ID') || '';

if (!token || !userId) {
    node.warn('LINE Messaging API not configured — set LINE_CHANNEL_ACCESS_TOKEN and LINE_USER_ID env vars');
    return null;
}

msg.headers = {
    'Authorization': 'Bearer ' + token,
    'Content-Type': 'application/json'
};
msg.payload = JSON.stringify({
    to: userId,
    messages: [{ type: 'text', text: msg.payload }]
});
return msg;

const url = env.get("TEAMS_WEBHOOK_URL") || "";

if (!url) {
    node.warn("MS Teams webhook not configured — set TEAMS_WEBHOOK_URL env var");
    return null;
}

const card = {
    "type": "message",
    "attachments": [{
        "contentType": "application/vnd.microsoft.card.adaptive",
        "contentUrl": null,
        "content": {
            "$schema": "http://adaptivecards.io/schemas/adaptive-card.json",
            "type": "AdaptiveCard",
            "version": "1.4",
            "body": [{
                "type": "TextBlock",
                "text": "IMS System Alert",
                "weight": "bolder",
                "size": "large",
                "color": "attention"
            }, {
                "type": "TextBlock",
                "text": msg.payload,
                "wrap": true,
                "spacing": "medium"
            }],
            "msteams": {
                "entities": []
            }
        }
    }]
};
msg.payload = JSON.stringify(card);
msg.headers = { "Content-Type": "application/json" };
msg.url = url;
return msg;

const apiKey = env.get('INGEST_API_KEY');
const reqApiKey = msg.req.get('x-api-key') || msg.req.query.key;

if (apiKey && reqApiKey !== apiKey) {
    return [null, msg];
}
return [msg, null];

msg.retryCount = (msg.retryCount || 0) + 1;
if (msg.retryCount <= 3) {
    node.warn('Alert delivery failed, retrying ' + msg.retryCount + '/3...');
    return [msg, null];
} else {
    node.error('Alert delivery failed permanently after 3 retries.');
    return [null, msg];
}
